#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5);

vec3 noise1 = lum(texture(sampler_noise_lq,
                  corr*vUv*4+ rand_frame));


vec2 hor = vec2 (.003,0);
vec2 ver = vec2 (0,.003);

float f0 = 1;
float dx = f0*lum(texture(sampler_main,vUv+hor)
         - texture(sampler_main,vUv-hor));
float dy = f0*lum(texture(sampler_main,vUv+ver)
         - texture(sampler_main,vUv-ver));

double2 zz = vec2(dx,dy);
float trel = uTime/3;
//zz = multiply(zz,mat2(_qb));

double3 crisp = texture(sampler_main,vUv+zz*.02);
crisp = pow(crisp,1) + .06*noise1 - length(zz)*.03 ;

double3 blur = GetBlur1(vUv);

ret = -blur*.1+ crisp;

 ret *= q32 ;
 ret -= 0.03;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//uv1 is rect. screen, center at (0;0)
vec2 uv1 = (vUv-0.5);// * uAspect.xy;

vec2 hor = vec2 (.002,0);
vec2 ver = vec2 (0,.002);

float f0 = .7;
float dx = f0*lum(texture(sampler_main,vUv+hor)
         - texture(sampler_main,vUv-hor));
float dy = f0*lum(texture(sampler_main,vUv+ver)
         - texture(sampler_main,vUv-ver));

vec2 dz = vec2 (dx,dy);
dz -= lum(GetPixel(vUv));

vec2 rs1 = multiply(16*uv1,mat2(_qb))+uTime/8;

vec3 canv1 = texture(sampler_main, (vUv-.5)*.95+.5);

float scale = 100;
rs1 = rs1 + dz*scale*.2;

float lava = texture(sampler_noise_hq,rs1/scale).x;
lava = clamp01(-q9*abs(lava) + 1);
vec3 lay1 = clamp01(vec3 (lava,lava*(lava-0.55)*2,(lava-1)*16));

ret = .6*lum(canv1-.05)*vec3 (1,1,1)  + lay1;

  fragColor = ret;
}
